t.script:
                //
(function(){
'use strict';
var bell=document.getElementById('adminNotifBell'),bellIcon=document.getElementById('adminBellIcon'),dropdown=document.getElementById('adminNotifDropdown'),badge=document.getElementById('adminNotifBadge'),list=document.getElementById('adminNotifList'),prevTotal=0;
bell.addEventListener('click',function(e){e.stopPropagation();dropdown.classList.toggle('open');});
document.addEventListener('click',function(){dropdown.classList.remove('open');});
dropdown.addEventListener('click',function(e){e.stopPropagation();});
document.getElementById('adminMarkAllRead').addEventListener('click',function(){
    fetch('/customer_support/admin/notifications/mark_read',{
        method:'POST',
        credentials:'same-origin',
        headers:{'Accept':'application/json'}
    })
    .then(function(r){if(!r.ok)throw new Error(r.status);return r.json();})
    .then(function(d){
        if(d&&d.success){
            list.querySelectorAll('.admin-notif-item').forEach(function(i){i.classList.remove('unread');});
            badge.classList.add('hidden');
            loadNotifications();
        }
    })
    .catch(function(e){console.warn('Admin mark-read failed:',e);});
});
document.getElementById('notifViewAllTickets').addEventListener('click',function(e){e.preventDefault();dropdown.classList.remove('open');var t=document.getElementById('ticket-assignment-tab');if(t)new bootstrap.Tab(t).show();});
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function loadNotifications(){fetch('/customer_support/admin/notifications',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}}).then(function(r){if(!r.ok)throw new Error(r.status);return r.json();}).then(function(d){renderNotifications(d);}).catch(function(e){console.warn('Admin notifications failed:',e);});}
function renderNotifications(data){var sla=data.sla_breaches||[],unassigned=data.unassigned||[],sc=data.status_changes||[];var total=sla.length+unassigned.length+sc.length;if(total===0){badge.classList.add('hidden');}else{badge.textContent=total>99?'99+':total;badge.classList.remove('hidden');if(total>prevTotal){bellIcon.classList.add('bell-ring');badge.classList.add('bump');setTimeout(function(){bellIcon.classList.remove('bell-ring');badge.classList.remove('bump');},600);}}prevTotal=total;if(total===0){list.innerHTML='<div class="admin-notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>All clear &#x2014; no active alerts!</div>';return;}var html='';if(sla.length>0){html+='<div class="admin-notif-section-label"><span><i class="bi bi-x-octagon-fill me-1" style="color:#ef4444;"></i>SLA Breaches</span><span class="section-count">'+sla.length+'</span></div>';html+=sla.map(function(a){return'<a class="admin-notif-item unread" href="/customer_support/admin_view/ticket/'+a.ticket_id+'"><div class="admin-notif-icon sla-breach"><i class="bi bi-x-octagon-fill"></i></div><div class="admin-notif-body"><div class="admin-notif-title">'+esc(a.ticket_name)+' &#x2014; '+esc(a.subject)+'</div><div class="admin-notif-sub">Agent: '+esc(a.agent_name)+' &middot; '+esc(a.time_display)+'</div><div class="admin-notif-time">Priority: '+esc(a.priority)+'</div></div><div class="admin-notif-dot sla-breach"></div></a>';}).join('');}if(unassigned.length>0){html+='<div class="admin-notif-section-label"><span><i class="bi bi-inbox-fill me-1" style="color:#059669;"></i>Unassigned Tickets</span><span class="section-count">'+unassigned.length+'</span></div>';html+=unassigned.map(function(t){return'<a class="admin-notif-item unread" href="/customer_support/admin_view/ticket/'+t.ticket_id+'"><div class="admin-notif-icon unassigned"><i class="bi bi-inbox-fill"></i></div><div class="admin-notif-body"><div class="admin-notif-title">'+esc(t.ticket_name)+' &#x2014; '+esc(t.subject)+'</div><div class="admin-notif-sub">Waiting '+esc(t.waiting)+' &middot; Priority: '+esc(t.priority)+'</div><div class="admin-notif-time">Created: '+esc(t.create_date)+'</div></div><div class="admin-notif-dot unassigned"></div></a>';}).join('');}if(sc.length>0){html+='<div class="admin-notif-section-label"><span><i class="bi bi-arrow-left-right me-1" style="color:#10b981;"></i>Recent Status Changes</span><span class="section-count">'+sc.length+'</span></div>';html+=sc.map(function(s){return'<a class="admin-notif-item" href="/customer_support/admin_view/ticket/'+s.ticket_id+'"><div class="admin-notif-icon status-chg"><i class="bi bi-arrow-left-right"></i></div><div class="admin-notif-body"><div class="admin-notif-title">'+esc(s.ticket_name)+' &#x2014; '+esc(s.subject)+'</div><div class="admin-notif-sub">&#x2192; '+esc(s.new_state)+' &middot; Agent: '+esc(s.agent_name)+'</div><div class="admin-notif-time">'+esc(s.changed_at)+'</div></div><div class="admin-notif-dot status-chg"></div></a>';}).join('');}list.innerHTML=html;}
document.addEventListener('DOMContentLoaded',function(){loadNotifications();setInterval(loadNotifications,30000);});
})();
//

                //
(function(){
'use strict';
var panel=document.getElementById('workloadPanel'),overlay=document.getElementById('workloadOverlay'),btn=document.getElementById('workloadBtn'),closeBtn=document.getElementById('workloadClose'),body=document.getElementById('workloadPanelBody'),lastUpd=document.getElementById('workloadLastUpdated'),refreshBtn=document.getElementById('workloadRefreshBtn');
function openPanel(){panel.classList.add('open');overlay.classList.add('open');btn.classList.add('active');}
function closePanel(){panel.classList.remove('open');overlay.classList.remove('open');btn.classList.remove('active');}
btn.addEventListener('click',function(){panel.classList.contains('open')?closePanel():openPanel();});
closeBtn.addEventListener('click',closePanel);overlay.addEventListener('click',closePanel);refreshBtn.addEventListener('click',loadWorkload);
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function loadWorkload(){lastUpd.textContent='Refreshing...';fetch('/customer_support/admin/workload',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}}).then(function(r){if(!r.ok)throw new Error(r.status);return r.json();}).then(function(d){renderWorkload(d);}).catch(function(e){console.warn('Workload failed:',e);body.innerHTML='<div class="workload-empty"><i class="bi bi-exclamation-triangle" style="font-size:2rem;color:#f59e0b;display:block;margin-bottom:.5rem;"></i>Failed to load workload data.</div>';});}
function renderWorkload(data){var agents=data.agents||[],summary=data.summary||{};var now=new Date();lastUpd.textContent='Updated at '+now.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});document.getElementById('ws-agents').textContent=summary.total_agents||agents.length;document.getElementById('ws-total-open').textContent=summary.total_open||0;document.getElementById('ws-overloaded').textContent=summary.overloaded||0;document.getElementById('ws-breached').textContent=summary.total_breached||0;if(agents.length===0){body.innerHTML='<div class="workload-empty"><i class="bi bi-people" style="font-size:2.5rem;display:block;margin-bottom:.5rem;"></i>No agents found.</div>';return;}body.innerHTML=agents.map(function(a){var status=a.total_open>8?'red':a.total_open>=5?'amber':'ok';var pillLabel=status==='red'?'Overloaded':status==='amber'?'Busy':'Available';var barColor=a.resolve_rate>=75?'#22c55e':a.resolve_rate>=50?'#f59e0b':'#ef4444';var wPct=Math.min(100,Math.round((a.total_open/10)*100));var wColor=status==='red'?'#ef4444':status==='amber'?'#f59e0b':'#22c55e';var avatar='/web/image/res.users/'+a.user_id+'/avatar_128';return'<div class="workload-card status-'+status+'"><div class="workload-agent-row"><img class="workload-agent-avatar" src="'+avatar+'" onerror="this.src=\'/web/static/img/avatar_gray.svg\'"/><div><div class="workload-agent-name">'+esc(a.name)+'</div><div class="workload-agent-sub">'+esc(a.email||'Support Agent')+'</div></div><span class="workload-status-pill '+status+'">'+pillLabel+'</span></div><div class="workload-stats-row"><div class="workload-stat-box"><div class="workload-stat-val">'+a.assigned+'</div><div class="workload-stat-lbl">Assigned</div></div><div class="workload-stat-box"><div class="workload-stat-val">'+a.in_progress+'</div><div class="workload-stat-lbl">In Progress</div></div><div class="workload-stat-box"><div class="workload-stat-val">'+a.resolved+'</div><div class="workload-stat-lbl">Resolved</div></div><div class="workload-stat-box"><div class="workload-stat-val">'+(a.breached>0?'<span style="color:#ef4444;font-weight:800;">'+a.breached+'</span>':a.breached)+'</div><div class="workload-stat-lbl">Breached</div></div></div><div class="workload-bar-wrap"><div class="workload-bar-label"><span>Workload</span><span>'+a.total_open+' / 10 open</span></div><div class="workload-bar-bg"><div class="workload-bar-fill" style="width:'+wPct+'%;background:'+wColor+';"></div></div></div><div class="workload-bar-wrap"><div class="workload-bar-label"><span>Resolve Rate</span><span>'+a.resolve_rate+'%</span></div><div class="workload-bar-bg"><div class="workload-bar-fill" style="width:'+a.resolve_rate+'%;background:'+barColor+';"></div></div></div></div>';}).join('');}
document.addEventListener('DOMContentLoaded',function(){loadWorkload();setInterval(loadWorkload,60000);});
})();
//

                //
(function(){
'use strict';
var PL={any:'Any',low:'Low',medium:'Medium',high:'High',urgent:'Urgent'};
var PC={any:'secondary',low:'info',medium:'primary',high:'warning',urgent:'danger'};
function escHtml(v){return String(v||'').replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
function slaAlert(msg,type){var el=document.getElementById('slaAlert');if(!el)return;el.className='alert alert-'+(type||'success')+' mb-3';el.textContent=msg;setTimeout(function(){el.className='d-none';},4000);}
function slaLoadPolicies(){var tb=document.getElementById('slaPoliciesBody');if(!tb)return;tb.innerHTML='<tr><td colspan="5" class="text-center text-muted py-3"><div class="spinner-border spinner-border-sm me-2" role="status"></div>Loading SLA policies...</td></tr>';fetch('/customer_support/sla/policies',{credentials:'same-origin',headers:{'Accept':'application/json'}}).then(function(r){return r.text().then(function(txt){return {ok:r.ok,text:txt,contentType:(r.headers.get('content-type')||'')};});}).then(function(resp){if(resp.contentType.indexOf('application/json')===-1){throw new Error('Your session may have expired. Please refresh and sign in again.');}var d={};try{d=JSON.parse(resp.text||'{}');}catch(parseErr){throw new Error('Invalid SLA response received from server.');}if(!resp.ok||d.success===false){throw new Error(d.error||('Request failed ('+(resp.ok?'unknown':'http')+')'));}if(!d.policies||!d.policies.length){tb.innerHTML='<tr><td colspan="5" class="text-center text-muted py-3"><i class="bi bi-inbox me-2"></i>No SLA policies defined yet.</td></tr>';return;}tb.innerHTML=d.policies.map(function(p){var policyPayload=encodeURIComponent(JSON.stringify(p));return'<tr><td><strong>'+escHtml(p.name)+'</strong></td><td><span class="badge bg-dark">'+escHtml(p.response_time)+' '+escHtml(p.time_unit)+'</span></td><td><span class="badge bg-'+(PC[p.priority_level]||'secondary')+'">'+escHtml(PL[p.priority_level]||p.priority_level)+'</span></td><td><small class="text-muted">'+escHtml(p.description||'-')+'</small></td><td><button class="btn btn-sm btn-outline-primary me-1 js-sla-edit" data-policy="'+policyPayload+'"><i class="bi bi-pencil"></i></button><button class="btn btn-sm btn-outline-danger js-sla-delete" data-policy-id="'+escHtml(p.id)+'" data-policy-name="'+escHtml(p.name)+'"><i class="bi bi-trash3"></i></button></td></tr>';}).join('');}).catch(function(e){console.warn('SLA load failed:',e);tb.innerHTML='<tr><td colspan="5" class="text-center text-danger py-3"><i class="bi bi-exclamation-triangle me-2"></i>'+escHtml(e.message||'Failed to load SLA policies')+'</td></tr>';slaAlert(e.message||'Failed to load SLA policies','danger');});}
window.slaCreate=function(e){e.preventDefault();var form=document.getElementById('slaCreateForm');var data=new FormData(form);var csrf=document.querySelector('input[name="csrf_token"]');if(csrf)data.set('csrf_token',csrf.value);fetch('/customer_support/sla/create',{method:'POST',credentials:'same-origin',body:new URLSearchParams(data)}).then(function(r){if(r.redirected||r.ok){slaAlert('SLA policy created!','success');form.reset();slaLoadPolicies();}else{slaAlert('Failed.','danger');}}).catch(function(){slaAlert('Network error.','danger');});};
window.slaOpenEdit=function(p){document.getElementById('editSlaId').value=p.id;document.getElementById('editSlaName').value=p.name;document.getElementById('editSlaTime').value=p.response_time;document.getElementById('editSlaUnit').value=p.time_unit;document.getElementById('editSlaPriority').value=p.priority_level;document.getElementById('editSlaDesc').value=p.description||'';new bootstrap.Modal(document.getElementById('slaEditModal')).show();};
window.slaSaveEdit=function(){var id=document.getElementById('editSlaId').value;var data=new URLSearchParams({sla_name:document.getElementById('editSlaName').value,sla_response_time:document.getElementById('editSlaTime').value,sla_time_unit:document.getElementById('editSlaUnit').value,sla_priority_level:document.getElementById('editSlaPriority').value,sla_description:document.getElementById('editSlaDesc').value});var csrf=document.querySelector('input[name="csrf_token"]');if(csrf)data.set('csrf_token',csrf.value);fetch('/customer_support/sla/'+id+'/update',{method:'POST',credentials:'same-origin',body:data}).then(function(r){return r.json();}).then(function(d){bootstrap.Modal.getInstance(document.getElementById('slaEditModal')).hide();if(d.success){slaAlert('Updated.','success');slaLoadPolicies();}else{slaAlert('Failed:'+(d.error||'unknown'),'danger');}});};
window.slaDelete=function(id,name){if(!confirm('Delete "'+name+'"?'))return;fetch('/customer_support/sla/'+id+'/delete',{method:'POST',credentials:'same-origin'}).then(function(r){return r.json();}).then(function(d){if(d.success){slaAlert('Deleted.','success');slaLoadPolicies();}else{slaAlert('Delete failed.','danger');}});};
document.addEventListener('DOMContentLoaded',function(){
    var m=document.getElementById('ticketSettingsModal');
    var slaTabBtn=document.querySelector('#ticketSettingsModal [data-bs-target="#slaTab"]');

    if(m){
        m.addEventListener('shown.bs.modal',function(){
            if(slaTabBtn){
                new bootstrap.Tab(slaTabBtn).show();
            }
            slaLoadPolicies();
        });
    }

    if(slaTabBtn){
        slaTabBtn.addEventListener('shown.bs.tab',function(){
            slaLoadPolicies();
        });
    }

    document.querySelectorAll('[data-bs-target="#ticketSettingsModal"]').forEach(function(btn){
        btn.addEventListener('click',function(){
            setTimeout(function(){
                slaLoadPolicies();
            },200);
        });
    });

    slaLoadPolicies();

    var body=document.getElementById('slaPoliciesBody');
    if(body)body.addEventListener('click',function(e){
        var editBtn=e.target.closest('.js-sla-edit');
        if(editBtn){
            var payload=editBtn.getAttribute('data-policy');
            if(payload){
                try{window.slaOpenEdit(JSON.parse(decodeURIComponent(payload)));}
                catch(err){console.warn('Invalid SLA payload',err);slaAlert('Could not open SLA policy editor.','danger');}
            }
            return;
        }

        var delBtn=e.target.closest('.js-sla-delete');
        if(delBtn){
            window.slaDelete(delBtn.getAttribute('data-policy-id'),delBtn.getAttribute('data-policy-name')||'policy');
        }
    });
});
})();
//

                //
(function () {
'use strict';

function gsAlert(msg, type) {
    var el = document.getElementById('gsAlert');
    if (!el) return;
    el.className = 'alert alert-' + (type || 'success') + ' mb-3';
    el.textContent = msg;
    if (type === 'success') setTimeout(function () { el.className = 'd-none'; }, 3500);
}

window.saveGeneralSettings = function () {
    var nameEl = document.getElementById('gsSystemName');
    var tzEl   = document.getElementById('gsTimezone');
    var btn    = document.getElementById('gsSaveBtn');
    if (!nameEl || !tzEl || !btn) return;

    var name = nameEl.value.trim();
    var tz   = tzEl.value;

    if (!name) { gsAlert('System name cannot be empty.', 'danger'); nameEl.focus(); return; }

    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm me-2" role="status"></span>Saving…';

    jsonCall('/customer_support/admin_dashboard/general_settings/save', {
        system_name: name,
        timezone: tz
    }).then(function (res) {
        btn.disabled = false;
        btn.innerHTML = '<i class="bi bi-save me-2"></i>Save Changes';
        if (res && res.success) {
            gsAlert('Settings saved successfully.', 'success');
            var brandEl = document.querySelector('.drawer-brand-text strong');
            if (brandEl) brandEl.textContent = name;
            document.title = name + ' — Admin Dashboard';
        } else {
            gsAlert((res && res.error) || 'Failed to save settings.', 'danger');
        }
    }).catch(function () {
        btn.disabled = false;
        btn.innerHTML = '<i class="bi bi-save me-2"></i>Save Changes';
        gsAlert('Network error. Please try again.', 'danger');
    });
};

window.filterGsTz = function (query) {
    var sel = document.getElementById('gsTimezone');
    if (!sel) return;
    var q = query.toLowerCase().replace(/\s+/g, '_');
    Array.prototype.forEach.call(sel.options, function (opt) {
        var match = opt.value.toLowerCase().indexOf(q) !== -1 ||
                    opt.text.toLowerCase().indexOf(query.toLowerCase()) !== -1;
        opt.style.display = match ? '' : 'none';
    });
    Array.prototype.forEach.call(sel.querySelectorAll('optgroup'), function (og) {
        var anyVisible = Array.prototype.some.call(og.querySelectorAll('option'), function (o) {
            return o.style.display !== 'none';
        });
        og.style.display = anyVisible ? '' : 'none';
    });
};

document.addEventListener('DOMContentLoaded', function () {
    var gsModal = document.getElementById('generalSettingsModal');
    if (gsModal) {
        gsModal.addEventListener('show.bs.modal', function () {
            var el = document.getElementById('gsAlert');
            if (el) el.className = 'd-none';
            var search = document.getElementById('gsTzSearch');
            if (search) { search.value = ''; filterGsTz(''); }
        });
    }
});

})();
//

                //
(function(){
'use strict';
var INTERVAL=15000;
var A=[{key:'open_tickets',sel:'[data-key="open_tickets"] .stat-value'},{key:'total_tickets',sel:'[data-key="total_tickets"] .stat-value'},{key:'high_priority',sel:'[data-key="high_priority"] .stat-value'},{key:'urgent',sel:'[data-key="urgent"] .stat-value'},{key:'avg_open_hours',sel:'[data-key="avg_open_hours"] .stat-value'},{key:'total_hours',sel:'[data-key="total_hours"] .stat-value'},{key:'avg_high_hours',sel:'[data-key="avg_high_hours"] .stat-value'},{key:'avg_urgent_hours',sel:'[data-key="avg_urgent_hours"] .stat-value'},{key:'resolved_tickets',sel:'[data-key="resolved_tickets"] .stat-value'},{key:'solve_rate',sel:'[data-key="solve_rate"] .stat-value',sfx:'%'},{key:'high_resolved',sel:'[data-key="high_resolved"] .stat-value'},{key:'urgent_resolved',sel:'[data-key="urgent_resolved"] .stat-value'}];
var P=[{key:'today_closed',sel:'[data-key="today_closed"] .performance-value'},{key:'avg_resolve_rate',sel:'[data-key="avg_resolve_rate"] .performance-value',sfx:'%'},{key:'daily_target',sel:'[data-key="daily_target"] .performance-value',sfx:'%'},{key:'achievement',sel:'[data-key="achievement"] .performance-value',sfx:'%'},{key:'sample_performance',sel:'[data-key="sample_performance"] .score-badge',sfx:'%'}];
var C=[{key:'new',sel:'[data-key="count_new"] .quick-stat-value'},{key:'assigned',sel:'[data-key="count_assigned"] .quick-stat-value'},{key:'resolved',sel:'[data-key="count_resolved"] .quick-stat-value'},{key:'total',sel:'[data-key="count_total"] .quick-stat-value'}];
function upd(sel,val,sfx){var el=document.querySelector(sel);if(el)el.textContent=val+(sfx||'');}
function flash(sel){var el=document.querySelector(sel);if(el){el.style.transition='color 0.3s';el.style.color='#1e88c7';setTimeout(function(){el.style.color='';},600);}}
function updBar(v){var b=document.querySelector('.progress-bar');if(b){b.style.width=v+'%';b.className='progress-bar '+(v>=80?'bg-success':'bg-warning');}}
function updBarLabel(v){var ls=document.querySelectorAll('.progress-label span');if(ls.length>=2)ls[1].textContent=v+'%';}
function updTime(){var t=new Date().toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});document.querySelectorAll('.last-updated').forEach(function(el){el.innerHTML='<i class="bi bi-clock me-1"></i>Updated at '+t;});}
function run(){fetch('/customer_support/dashboard/analytics',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}}).then(function(r){if(!r.ok)throw new Error(r.status);return r.json();}).then(function(d){var a=d.analytics||{},p=d.performance||{},c=d.ticket_counts||{};A.forEach(function(i){var v=a[i.key];if(v!==undefined){upd(i.sel,v,i.sfx||'');flash(i.sel);}});P.forEach(function(i){var v=p[i.key];if(v!==undefined)upd(i.sel,v,i.sfx||'');});if(p.achievement!==undefined){updBar(p.achievement);updBarLabel(p.achievement);}C.forEach(function(i){var v=c[i.key];if(v!==undefined)upd(i.sel,v,'');});updTime();}).catch(function(e){console.warn('Analytics refresh failed:',e);});}
document.addEventListener('DOMContentLoaded',function(){run();setInterval(run,INTERVAL);});
})();
//

                //
(function(){
'use strict';
function activateTabOnly(tabId){
  var ts='#'+tabId;var tb=document.querySelector('.header-left button[data-bs-target="'+ts+'"]');
  if(!tb)return;
  document.querySelectorAll('.header-left button').forEach(function(b){b.classList.remove('active');b.setAttribute('aria-selected','false');});
  document.querySelectorAll('.tab-pane').forEach(function(p){p.classList.remove('show','active');});
  tb.classList.add('active');tb.setAttribute('aria-selected','true');
  var tp=document.querySelector(ts);if(tp)tp.classList.add('show','active');
}
window._activateTab=activateTabOnly;
function _initTabs(){
  // Read all params up front BEFORE cleaning the URL
  var urlParams=new URLSearchParams(window.location.search);
  var tabParam=urlParams.get('tab');
  var hashParam=window.location.hash.substring(1);
  var targetTab=tabParam||hashParam;
  var ticketModal=urlParams.get('ticket_modal'); // kept for the ticket-modal IIFE that reads it
  var projCreated=urlParams.get('project_created');
  var projCreatedId=urlParams.get('project_id');
  // Activate tab via manual class manipulation (no shown.bs.tab fires here)
  if(targetTab)activateTabOnly(targetTab);
  // Fully clean the URL — strip ALL server-redirect params (success, error, tab, modal, etc.)
  // Only preserve ticket_modal because the ticket quick-view IIFE reads it in its own DOMContentLoaded
  var kept=new URLSearchParams();
  if(ticketModal)kept.set('ticket_modal',ticketModal);
  var clean=kept.toString();
  history.replaceState({tab:targetTab||'overview'},'',window.location.pathname+(clean?('?'+clean):''));
  // After project creation, auto-open the drawer for the new project card
    if(projCreated&&projCreatedId){setTimeout(function(){var card=document.getElementById('pjCard-'+projCreatedId);if(card&&typeof openProjDrawer==='function')openProjDrawer(card.dataset);},400);}
  // Wire tab button clicks — use capture phase so our handler fires before Bootstrap's own handler,
  // preventing Bootstrap from also calling show() and firing shown.bs.tab a second time
  var tl=[].slice.call(document.querySelectorAll('.header-left button[data-bs-toggle="tab"]'));
  tl.forEach(function(t){t.addEventListener('click',function(e){e.preventDefault();new bootstrap.Tab(t).show();},true);});
  tl.forEach(function(t){t.addEventListener('shown.bs.tab',function(e){
    var tabId=e.target.getAttribute('data-bs-target').substring(1);
    localStorage.setItem('activeDashboardTab',e.target.getAttribute('data-bs-target'));
    history.pushState({tab:tabId},'',tabId==='overview'?window.location.pathname:window.location.pathname+'?tab='+tabId);
  });});
  document.querySelectorAll('.action-card[data-bs-toggle="tab"]').forEach(function(c){c.addEventListener('click',function(e){e.preventDefault();var t=document.querySelector('.header-left button[data-bs-target="'+this.getAttribute('href')+'"]');if(t)new bootstrap.Tab(t).show();});});
  document.querySelectorAll('.alert-success,.alert-danger').forEach(function(a){setTimeout(function(){new bootstrap.Alert(a).close();},5000);});
}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',_initTabs);}else{_initTabs();}
})();
