(function(){
'use strict';
function esc(v){return String(v||'').replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
function toTitle(v){v=String(v||'').replace(/_/g,' ');return v.charAt(0).toUpperCase()+v.slice(1);}
var modalEl=document.getElementById('adminTicketQuickView');
if(!modalEl){return;}
var modal=new bootstrap.Modal(modalEl);
var loadingEl=document.getElementById('aqvLoading');
var contentEl=document.getElementById('aqvContent');
var errorEl=document.getElementById('aqvError');

function setLoading(){loadingEl.style.display='block';contentEl.style.display='none';errorEl.style.display='none';}
function setError(msg){loadingEl.style.display='none';contentEl.style.display='none';errorEl.textContent=msg||'Could not load ticket details.';errorEl.style.display='block';}

function render(data){
    var t=data.ticket||{};
    document.getElementById('aqvTicketName').textContent=t.name||('#'+(t.id||''));
    document.getElementById('aqvTicketSubject').textContent=t.subject||'';
    document.getElementById('aqvClient').textContent=t.customer||'-';
    document.getElementById('aqvCreated').textContent=t.created_on||'-';
    document.getElementById('aqvAssigned').textContent=t.assigned_to||'Unassigned';
    document.getElementById('aqvProject').textContent=t.project||'-';
    document.getElementById('aqvPriority').innerHTML='<span class="priority-badge priority-'+esc((t.priority||'').toLowerCase())+'">'+esc(toTitle(t.priority||'-'))+'</span>';
    document.getElementById('aqvStatus').innerHTML='<span class="status-badge status-'+esc((t.state||'').toLowerCase())+'">'+esc(toTitle(t.state||'-'))+'</span>';
    document.getElementById('aqvDescription').textContent=t.description||'No description provided.';

    var aWrap=document.getElementById('aqvAttachments');
    var attachments=t.attachments||[];
    if(!attachments.length){
        aWrap.innerHTML='<div class="text-muted small">No attachments available.</div>';
    } else {
        aWrap.innerHTML=attachments.map(function(a){
            return '<a class="aqv-attach-item" href="'+esc(a.url)+'" target="_blank" rel="noopener"><i class="bi bi-paperclip"></i><span>'+esc(a.name)+'</span></a>';
        }).join('');
    }

    loadingEl.style.display='none';
    errorEl.style.display='none';
    contentEl.style.display='block';
}

function loadTicket(ticketId){
    if(!ticketId){return;}
    setLoading();
    modal.show();
    fetch('/customer_support/admin/ticket/'+ticketId+'/quick_view',{credentials:'same-origin',headers:{'Accept':'application/json'}})
        .then(function(r){if(!r.ok){throw new Error('HTTP '+r.status);}return r.json();})
        .then(function(d){if(!d.success){throw new Error(d.error||'Unable to load ticket.');}render(d);})
        .catch(function(e){setError(e.message||'Unable to load ticket details.');});
}

document.addEventListener('click',function(e){
    var link=e.target.closest('.admin-ticket-open');
    if(!link){return;}
    e.preventDefault();
    var ticketId=link.getAttribute('data-ticket-id');
    loadTicket(ticketId);
});

document.addEventListener('DOMContentLoaded',function(){
    var p=new URLSearchParams(window.location.search);
    var ticketModalId=p.get('ticket_modal');
    if(ticketModalId){
        var tabBtn=document.getElementById('ticket-assignment-tab');
        if(tabBtn){new bootstrap.Tab(tabBtn).show();}
        setTimeout(function(){loadTicket(ticketModalId);},250);
        p.delete('ticket_modal');
        var clean=p.toString();
        var next=window.location.pathname+(clean?('?'+clean):'')+window.location.hash;
        window.history.replaceState({},'',next);
    }
});
})();
