(function(){
'use strict';
document.addEventListener('DOMContentLoaded',function(){
    var filterWrap=document.getElementById('umRoleFilters');
    var table=document.getElementById('umUsersTable');
    var noResults=document.getElementById('umNoResultsRow');
    if(filterWrap&&table&&noResults){
        var userRows=Array.prototype.slice.call(table.querySelectorAll('tbody tr[data-role]'));

        function applyFilter(filterValue){
            var visibleCount=0;
            userRows.forEach(function(row){
                var role=row.getAttribute('data-role')||'';
                var shouldShow=filterValue==='all'||role===filterValue;
                row.style.display=shouldShow?'':'none';
                if(shouldShow){visibleCount+=1;}
            });
            noResults.classList.toggle('d-none',visibleCount!==0);
        }

        filterWrap.addEventListener('click',function(e){
            var btn=e.target.closest('button[data-role-filter]');
            if(!btn){return;}
            filterWrap.querySelectorAll('button[data-role-filter]').forEach(function(item){
                item.classList.remove('active');
            });
            btn.classList.add('active');
            applyFilter(btn.getAttribute('data-role-filter'));
        });

        applyFilter('all');
    }

    var deleteModalEl=document.getElementById('userDeleteConfirmModal');
    var deleteMsgEl=document.getElementById('userDeleteConfirmText');
    var confirmDeleteBtn=document.getElementById('confirmUserDeleteBtn');
    var pendingDeleteForm=null;

    if(deleteModalEl&&confirmDeleteBtn&&deleteMsgEl){
        var deleteModal=new bootstrap.Modal(deleteModalEl);

        document.querySelectorAll('.js-user-delete-form').forEach(function(form){
            form.addEventListener('submit',function(e){
                e.preventDefault();
                pendingDeleteForm=form;
                var userName=form.getAttribute('data-user-name')||'this user';
                deleteMsgEl.textContent='User: '+userName+'. This action will archive access until the user is reactivated.';
                deleteModal.show();
            });
        });

        confirmDeleteBtn.addEventListener('click',function(){
            if(pendingDeleteForm){
                pendingDeleteForm.submit();
            }
        });

        deleteModalEl.addEventListener('hidden.bs.modal',function(){
            pendingDeleteForm=null;
        });
    }
});

window.showUserDetail = function(userId) {
    var modalEl = document.getElementById('userDetailModal');
    var bodyEl  = document.getElementById('userDetailBody');
    var nameEl  = document.getElementById('userDetailName');
    if (!modalEl) return;
    nameEl.textContent = 'Loading…';
    bodyEl.innerHTML   = '<div class="text-center py-4"><div class="spinner-border spinner-border-sm text-secondary"></div></div>';
    new bootstrap.Modal(modalEl).show();

    fetch('/customer_support/admin_dashboard/user/' + userId + '/detail', {
        method: 'POST',
        credentials: 'same-origin',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: 1, params: {} })
    })
    .then(function(r) { return r.json(); })
    .then(function(resp) {
        var d = resp.result || {};
        if (!d.success || !d.user) {
            bodyEl.innerHTML = '<div class="alert alert-danger">' + (d.error || 'Failed to load user details.') + '</div>';
            return;
        }
        var u = d.user;
        nameEl.textContent = u.name;

        var roleBadgeClass = u.role === 'Focal Person' ? 'bg-info' : u.role === 'Admin' ? 'bg-primary' : 'bg-secondary';
        var statusBadge    = u.active
            ? '<span class="badge bg-success"><i class="bi bi-check-circle me-1"></i>Active</span>'
            : '<span class="badge bg-secondary"><i class="bi bi-x-circle me-1"></i>Inactive</span>';

        var projectsHtml = '';
        if (u.projects && u.projects.length) {
            var rows = u.projects.map(function(p) {
                return '<tr><td class="fw-semibold">' + (p.name || '') + '</td>'
                    + '<td><span class="badge bg-light text-dark border">' + (p.key || '-') + '</span></td>'
                    + '<td class="text-muted" style="font-size:.82rem;">' + (p.association || '') + '</td></tr>';
            }).join('');
            projectsHtml = '<div class="mt-3">'
                + '<div style="font-size:.72rem;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#064e3b;border-bottom:2px solid #064e3b;padding-bottom:.3rem;margin-bottom:.6rem;">Associated Projects</div>'
                + '<table class="table table-sm table-hover mb-0"><thead><tr>'
                + '<th style="font-size:.75rem;">Project</th><th style="font-size:.75rem;">Key</th><th style="font-size:.75rem;">Association</th>'
                + '</tr></thead><tbody>' + rows + '</tbody></table></div>';
        } else {
            projectsHtml = '<p class="text-muted mt-3 mb-0" style="font-size:.85rem;"><i class="bi bi-info-circle me-1"></i>No projects associated.</p>';
        }

        bodyEl.innerHTML =
            '<div class="d-flex align-items-center gap-3 mb-3">'
            + '<div style="width:48px;height:48px;border-radius:50%;background:#e9ecef;display:flex;align-items:center;justify-content:center;font-size:1.4rem;color:#6c757d;"><i class="bi bi-person-fill"></i></div>'
            + '<div>'
            + '<div class="fw-bold fs-6">' + u.name + '</div>'
            + '<div class="text-muted" style="font-size:.85rem;">' + u.email + '</div>'
            + '</div>'
            + '</div>'
            + '<div class="d-flex gap-2 mb-1">'
            + '<span class="badge ' + roleBadgeClass + '">' + u.role + '</span>'
            + statusBadge
            + '</div>'
            + projectsHtml;
    })
    .catch(function() {
        bodyEl.innerHTML = '<div class="alert alert-danger">Network error loading user details.</div>';
    });
};
})();
