(function(){
'use strict';
var CAT_LABELS={company:'Company Info',services:'Services & Products',projects:'Projects',pricing:'Pricing',technical:'Technical Docs',faq:'FAQ',other:'Other'};
function kbAlert(msg,type){var el=document.getElementById('kbAlert');if(!el)return;el.className='alert alert-'+(type||'success')+' mb-3';el.textContent=msg;el.classList.remove('d-none');setTimeout(function(){el.classList.add('d-none');},4000);}
function kbLoadDocs(){var url='/customer_support/knowledge/list?_ts='+Date.now();fetch(url,{credentials:'same-origin',cache:'no-store',headers:{'Accept':'application/json','Cache-Control':'no-cache'}}).then(function(r){return r.json();}).then(function(data){var docs=data.documents||[];document.getElementById('kbTotalDocs').textContent=docs.length;document.getElementById('kbReadyDocs').textContent=docs.filter(function(d){return d.state==='ready';}).length;document.getElementById('kbPendingDocs').textContent=docs.filter(function(d){return d.state==='pending';}).length;document.getElementById('kbErrorDocs').textContent=docs.filter(function(d){return d.state==='error';}).length;var tb=document.getElementById('kbDocsBody');if(!docs.length){tb.innerHTML='<tr><td colspan="8" class="text-center text-muted py-4"><i class="bi bi-folder2-open me-2"></i>No documents uploaded yet. Upload your first document above.</td></tr>';return;}tb.innerHTML=docs.map(function(d){var stateBadge=d.state==='ready'?'<span class="badge bg-success">&#x2705; Ready</span>':d.state==='error'?'<span class="badge bg-danger" title="'+(d.error_msg||'')+'">&#x274C; Error</span>':'<span class="badge bg-warning text-dark">&#x23F3; Pending</span>';var typeBadge={pdf:'<span class="badge bg-danger">PDF</span>',docx:'<span class="badge bg-primary">DOCX</span>',txt:'<span class="badge bg-success">TXT</span>',xlsx:'<span class="badge bg-info text-dark">XLSX</span>'}[d.file_type]||'<span class="badge bg-secondary">FILE</span>';var projectBadge=d.project_name?'<span class="badge bg-info text-dark">'+d.project_name+'</span>':'<span class="text-muted" style="font-size:0.75rem;">—</span>';return'<tr><td><strong>'+d.name+'</strong>'+(d.description?'<br><small class="text-muted">'+d.description+'</small>':'')+'</td><td>'+projectBadge+'</td><td><span class="badge bg-secondary">'+(CAT_LABELS[d.category]||d.category)+'</span></td><td>'+typeBadge+'</td><td>'+stateBadge+'</td><td class="text-center fw-bold text-primary">'+(d.chunk_count||0)+'</td><td><small class="text-muted">'+(d.create_date||'')+'</small></td><td><button class="btn btn-sm btn-outline-danger" onclick="kbDelete('+d.id+',\''+d.name.replace(/'/g,"\\'")+'\')" title="Delete"><i class="bi bi-trash3"></i></button></td></tr>';}).join('');}).catch(function(e){console.warn('KB load failed:',e);});}
window.kbUpload=function(){var name=document.getElementById('kbDocName').value.trim();var category=document.getElementById('kbCategory').value;var desc=document.getElementById('kbDescription').value.trim();var fileEl=document.getElementById('kbFile');var projectId=document.getElementById('kbProjectSelect').value;if(!name||!fileEl.files.length){kbAlert('Please fill in the document name and select a file.','warning');return;}var allowed=['.pdf','.docx','.txt','.xlsx'];var filename=fileEl.files[0].name.toLowerCase();if(!allowed.some(function(ext){return filename.endsWith(ext);})){kbAlert('Invalid file type. Allowed: PDF, DOCX, TXT, XLSX','danger');return;}var formData=new FormData();formData.append('name',name);formData.append('category',category);formData.append('description',desc);formData.append('file',fileEl.files[0]);formData.append('ajax','1');if(projectId)formData.append('project_id',projectId);var csrf=document.querySelector('input[name="csrf_token"]');if(csrf)formData.append('csrf_token',csrf.value);var btn=document.getElementById('kbUploadBtn');if(btn){btn.disabled=true;btn.innerHTML='<i class="bi bi-hourglass-split me-2"></i>Uploading...';}fetch('/customer_support/knowledge/upload',{method:'POST',credentials:'same-origin',cache:'no-store',body:formData}).then(function(r){return r.json();}).then(function(res){if(!res||res.error){throw new Error((res&&res.error)||'Upload failed.');}var msg=projectId?'Document uploaded and linked to project. It will appear on the ticket board once processed.':'Document uploaded. Processing has started in the background.';kbAlert(msg,'success');document.getElementById('kbDocName').value='';document.getElementById('kbDescription').value='';document.getElementById('kbFile').value='';document.getElementById('kbProjectSelect').value='';kbLoadDocs();setTimeout(kbLoadDocs,400);}).catch(function(){kbAlert('Upload failed. Please try again.','danger');}).finally(function(){if(btn){btn.disabled=false;btn.innerHTML='<i class="bi bi-upload me-2"></i>Upload &amp; Process';}});};
window.kbDelete=function(id,name){if(!confirm('Delete "'+name+'"?\nThe AI will no longer use this document.'))return;var formData=new FormData();var csrf=document.querySelector('input[name="csrf_token"]');if(csrf)formData.append('csrf_token',csrf.value);fetch('/customer_support/knowledge/delete/'+id,{method:'POST',credentials:'same-origin',body:formData}).then(function(){kbAlert('Document deleted.','success');kbLoadDocs();}).catch(function(){kbAlert('Delete failed.','danger');});};
document.addEventListener('DOMContentLoaded',function(){var modal=document.getElementById('knowledgeBaseModal');if(modal)modal.addEventListener('shown.bs.modal',function(){kbLoadDocs();});});

/* ── DELETE PROJECT MODAL ──────────────────────────────────────────── */
window.openDeleteProjectModal = function(projectId, projectName) {
    document.getElementById('deleteProjectName').textContent = projectName;
    document.getElementById('deleteProjectForm').action =
        '/customer_support/admin_dashboard/projects/delete/' + projectId;
    var modal = new bootstrap.Modal(document.getElementById('deleteProjectModal'));
    modal.show();
};

/* ── PROJECT REPORTS MODAL ─────────────────────────────────────────── */
window.openProjectReportsModal = function() {
    var modal = new bootstrap.Modal(document.getElementById('projectReportsModal'));
    modal.show();
    prLoadReports();
};

function prLoadReports() {
    var container = document.getElementById('prReportsList');
    container.innerHTML = '<div class="text-center py-5 text-muted"><div class="spinner-border spinner-border-sm me-2"></div>Loading reports...</div>';
    fetch('/customer_support/admin_dashboard/project_reports', {
        method: 'POST',
        credentials: 'same-origin',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: 1, params: {} })
    })
    .then(function(r) { return r.json(); })
    .then(function(resp) {
        var data = resp.result || {};
        if (!data.success) {
            container.innerHTML = '<div class="alert alert-danger">Failed to load reports.</div>';
            return;
        }
        var reports = data.reports || [];
        if (!reports.length) {
            container.innerHTML =
                '<div class="text-center py-5 text-muted">' +
                '<i class="bi bi-file-earmark-x" style="font-size:2.5rem;display:block;margin-bottom:.75rem;opacity:.4;"></i>' +
                '<strong>No reports yet</strong><br>' +
                '<span style="font-size:.88rem;">Reports are generated automatically when a project is deleted.</span>' +
                '</div>';
            return;
        }
        var rows = reports.map(function(r) {
            var solved = r.total_tickets > 0
                ? Math.round(r.resolved_tickets / r.total_tickets * 100) : 0;
            return '<tr>' +
                '<td><strong>' + r.project_name + '</strong><br><span class="badge bg-info" style="font-size:.72rem;">' + r.project_key + '</span></td>' +
                '<td><span class="text-muted" style="font-size:.85rem;">' + r.start_date + ' &rarr; ' + r.end_date + '</span></td>' +
                '<td>' + r.total_tickets + '</td>' +
                '<td>' +
                    '<span class="badge bg-success me-1">' + r.resolved_tickets + ' resolved</span>' +
                    (r.open_tickets ? '<span class="badge bg-warning text-dark">' + r.open_tickets + ' open</span>' : '') +
                '</td>' +
                '<td><span class="badge ' + (solved >= 80 ? 'bg-success' : solved >= 50 ? 'bg-warning text-dark' : 'bg-danger') + '">' + solved + '%</span></td>' +
                '<td><small class="text-muted">' + r.generated_on + '</small></td>' +
                '<td><button class="btn btn-sm btn-outline-primary" onclick="prShowDetail(' + JSON.stringify(r).replace(/"/g, '&quot;') + ')">' +
                    '<i class="bi bi-eye"></i></button></td>' +
                '</tr>';
        }).join('');
        container.innerHTML =
            '<div class="table-responsive">' +
            '<table class="table table-hover align-middle">' +
            '<thead><tr>' +
            '<th>Project</th><th>Timeline</th><th>Tickets</th>' +
            '<th>Outcomes</th><th>Resolve Rate</th><th>Generated</th><th></th>' +
            '</tr></thead>' +
            '<tbody>' + rows + '</tbody>' +
            '</table></div>';
    })
    .catch(function() {
        container.innerHTML = '<div class="alert alert-danger">Network error loading reports.</div>';
    });
}

window._prCurrentReportId = null;

window.prShowDetail = function(r) {
    window._prCurrentReportId = r.id || null;
    var fwdBtn = document.getElementById('prForwardBtn');
    if (fwdBtn) { fwdBtn.disabled = false; fwdBtn.innerHTML = '<i class="bi bi-send me-1"></i>Forward to Customer'; fwdBtn.className = 'btn btn-outline-success'; }
    document.getElementById('prDetailTitle').textContent = r.project_name + ' — Project Closure Report';
    document.getElementById('prDetailSubtitle').textContent = 'Ref: ' + (r.project_key||'-') + '  ·  Generated ' + r.generated_on;

    var team      = Array.isArray(r.team) ? r.team : [];
    var customers = Array.isArray(r.customers) ? r.customers : [];
    var allTkts   = Array.isArray(r.all_ticket_details) ? r.all_ticket_details : [];
    var slaTotal  = r.sla_met + r.sla_breached;
    var slaRate   = slaTotal > 0 ? Math.round(r.sla_met / slaTotal * 100) : 0;
    var resolveRate = r.total_tickets > 0 ? Math.round(r.resolved_tickets / r.total_tickets * 100) : 0;
    var taskPct   = r.total_tasks > 0 ? Math.round(r.completed_tasks / r.total_tasks * 100) : 0;

    function esc(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

    /* ── SHARED STYLES ────────────────────────────────────────── */
    var S = {
        wrap:    'font-family:"Segoe UI",Arial,sans-serif;color:#1a1a2e;background:#fff;padding:2rem 2.2rem;',
        h2:      'margin:0;font-size:1.45rem;font-weight:700;letter-spacing:.5px;',
        secHead: 'font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:#064e3b;border-bottom:2px solid #064e3b;padding-bottom:.35rem;margin:1.4rem 0 .75rem;',
        label:   'font-size:.72rem;color:#6c757d;text-transform:uppercase;letter-spacing:.05em;',
        val:     'font-size:.9rem;font-weight:600;color:#1a1a2e;margin-top:.1rem;',
        th:      'padding:.55rem .7rem;text-align:left;font-size:.72rem;font-weight:700;text-transform:uppercase;letter-spacing:.06em;background:#064e3b;color:#fff;white-space:nowrap;',
        td:      'padding:.5rem .7rem;font-size:.8rem;border-bottom:1px solid #e9ecef;vertical-align:top;',
        tdBold:  'padding:.5rem .7rem;font-size:.8rem;border-bottom:1px solid #e9ecef;font-weight:700;',
    };

    function kv(label, value) {
        return '<div style="margin-bottom:.55rem;"><div style="' + S.label + '">' + label + '</div><div style="' + S.val + '">' + value + '</div></div>';
    }
    function secTitle(txt, newPage) {
        var pb = newPage ? 'page-break-before:always;break-before:page;' : '';
        return '<div style="' + S.secHead + pb + '">' + txt + '</div>';
    }
    function slaCell(status) {
        var breached = (status||'').toLowerCase() === 'breached';
        return '<span style="display:inline-block;padding:.15rem .5rem;border-radius:3px;font-size:.7rem;font-weight:700;' +
            (breached ? 'background:#fde8e6;color:#922b21;' : 'background:#d5f5e3;color:#1e8449;') + '">' +
            (breached ? 'BREACHED' : 'MET') + '</span>';
    }
    function stateCell(state) {
        var s = (state||'').toLowerCase();
        var bg = s.includes('resolv')||s.includes('clos') ? '#d5f5e3' : s.includes('progress') ? '#fef9e7' : '#f2f3f4';
        var clr= s.includes('resolv')||s.includes('clos') ? '#1e8449' : s.includes('progress') ? '#9a7d0a' : '#555';
        return '<span style="display:inline-block;padding:.15rem .45rem;border-radius:3px;font-size:.7rem;font-weight:600;background:' + bg + ';color:' + clr + ';">' + esc(state) + '</span>';
    }
    function priCell(p) {
        var s = (p||'').toLowerCase();
        var bg = s==='urgent'?'#fde8e6':s==='high'?'#fef3cd':s==='low'?'#f2f3f4':'#e8f4fd';
        var clr= s==='urgent'?'#922b21':s==='high'?'#9a7d0a':s==='low'?'#555':'#1a6a9a';
        return '<span style="display:inline-block;padding:.15rem .45rem;border-radius:3px;font-size:.7rem;font-weight:600;background:' + bg + ';color:' + clr + ';">' + esc(p) + '</span>';
    }
    function statBox(val, label, color) {
        return '<div style="flex:1;text-align:center;padding:.75rem .5rem;border:1px solid #e9ecef;border-radius:6px;border-top:3px solid ' + (color||'#064e3b') + ';">' +
            '<div style="font-size:1.5rem;font-weight:700;color:' + (color||'#1a1a2e') + ';">' + val + '</div>' +
            '<div style="font-size:.68rem;color:#6c757d;text-transform:uppercase;letter-spacing:.05em;margin-top:.2rem;">' + label + '</div></div>';
    }

    /* ── 1. DOCUMENT HEADER ───────────────────────────────────── */
    var headerHtml =
        '<div style="display:flex;justify-content:space-between;align-items:flex-start;padding-bottom:1.2rem;border-bottom:3px solid #064e3b;margin-bottom:1.2rem;page-break-inside:avoid;break-inside:avoid;">' +
        '<div>' +
        '<div style="font-size:.68rem;font-weight:700;text-transform:uppercase;letter-spacing:.15em;color:#6c757d;margin-bottom:.35rem;">Official Project Closure Report</div>' +
        '<div style="' + S.h2 + 'color:#064e3b;">' + esc(r.project_name) + '</div>' +
        '<div style="font-size:.82rem;color:#6c757d;margin-top:.25rem;">' + esc(r.project_type||'') + (r.project_key ? '&nbsp;&nbsp;|&nbsp;&nbsp;Ref: <strong>' + esc(r.project_key) + '</strong>' : '') + '</div>' +
        '</div>' +
        '<div style="text-align:right;">' +
        '<div style="font-size:.72rem;color:#6c757d;">Dragon Coders</div>' +
        '<div style="font-size:.68rem;color:#9ca3af;margin-top:.15rem;">Generated: ' + esc(r.generated_on) + '</div>' +
        '</div>' +
        '</div>';

    /* ── 2. PROJECT OVERVIEW ──────────────────────────────────── */
    var overviewHtml =
        secTitle('Project Overview') +
        '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:.5rem 1.5rem;page-break-inside:avoid;break-inside:avoid;">' +
        kv('Project Reference', esc(r.project_key||'-')) +
        kv('Project Type', esc(r.project_type||'-')) +
        kv('Focal Person', esc(r.focal_person||'-')) +
        kv('Warranty / Support Start', esc(r.start_date)) +
        kv('Warranty / Support End', esc(r.end_date)) +
        kv('Compliance', esc(r.compliance_flags||'None')) +
