        (r.project_goals ? '<div style="margin-top:.6rem;padding:.65rem .85rem;background:#f8f9fc;border-left:3px solid #064e3b;border-radius:0 4px 4px 0;font-size:.82rem;"><span style="' + S.label + '">Project Goals &amp; Objectives</span><p style="margin:.25rem 0 0;white-space:pre-line;color:#374151;">' + esc(r.project_goals) + '</p></div>' : '') +
        (r.tech_languages||r.tech_frameworks||r.tech_databases ?
            '<div style="margin-top:.5rem;font-size:.8rem;color:#374151;padding:.5rem .85rem;background:#f8f9fc;border-radius:4px;">' +
            (r.tech_languages ? '<strong>Languages:</strong> ' + esc(r.tech_languages) + '&emsp;' : '') +
            (r.tech_frameworks ? '<strong>Frameworks:</strong> ' + esc(r.tech_frameworks) + '&emsp;' : '') +
            (r.tech_databases  ? '<strong>Databases:</strong> ' + esc(r.tech_databases) : '') +
            '</div>' : '');

    /* ── 3. TEAM & CUSTOMERS ──────────────────────────────────── */
    var teamRows = team.map(function(m) {
        return '<tr><td style="' + S.td + '">' + esc(m.name) + '</td><td style="' + S.td + '">' + esc(m.role) + '</td></tr>';
    }).join('');
    var custRows = customers.map(function(c) {
        return '<tr><td style="' + S.td + '">' + esc(c.name) + '</td><td style="' + S.td + '">' + esc(c.email||'-') + '</td></tr>';
    }).join('');

    var teamCustHtml =
        secTitle('Project Team &amp; Customers') +
        '<div style="display:grid;grid-template-columns:1fr 1fr;gap:1rem;">' +
        '<div><div style="font-size:.75rem;font-weight:600;color:#064e3b;margin-bottom:.4rem;">Team Members</div>' +
        '<table style="width:100%;border-collapse:collapse;">' +
        '<thead><tr><th style="' + S.th + '">Name</th><th style="' + S.th + '">Role</th></tr></thead>' +
        '<tbody>' + (teamRows||'<tr><td colspan="2" style="' + S.td + 'color:#6c757d;">No team data.</td></tr>') + '</tbody></table></div>' +
        '<div><div style="font-size:.75rem;font-weight:600;color:#064e3b;margin-bottom:.4rem;">Customers Served</div>' +
        '<table style="width:100%;border-collapse:collapse;">' +
        '<thead><tr><th style="' + S.th + '">Name</th><th style="' + S.th + '">Email</th></tr></thead>' +
        '<tbody>' + (custRows||'<tr><td colspan="2" style="' + S.td + 'color:#6c757d;">No customer data.</td></tr>') + '</tbody></table></div>' +
        '</div>';

    /* ── 4. TICKET REGISTER (main table) ─────────────────────── */
    var ticketRows = allTkts.map(function(t, i) {
        return '<tr style="background:' + (i%2===0?'#fff':'#f8f9fc') + ';page-break-inside:avoid;break-inside:avoid;">' +
            '<td style="' + S.tdBold + '">' + esc(t.ticket_id) + '</td>' +
            '<td style="' + S.td + '">' + esc(t.subject) + (t.description ? '<br><span style="font-size:.72rem;color:#6c757d;">' + esc(t.description) + '</span>' : '') + '</td>' +
            '<td style="' + S.td + '">' + esc(t.customer) + '</td>' +
            '<td style="' + S.td + 'white-space:nowrap;">' + esc(t.raised_on) + '</td>' +
            '<td style="' + S.td + 'white-space:nowrap;">' + esc(t.resolved_on) + '</td>' +
            '<td style="' + S.td + '">' + esc(t.solved_by) + '</td>' +
            '<td style="' + S.td + '">' + priCell(t.priority) + '</td>' +
            '<td style="' + S.td + '">' + stateCell(t.state) + '</td>' +
            '<td style="' + S.td + '">' + slaCell(t.sla_status) + '</td>' +
            '</tr>';
    }).join('');

    var ticketRegisterHtml =
        secTitle('Ticket Register — Complete Record', true) +
        '<div style="overflow-x:auto;">' +
        '<table style="width:100%;border-collapse:collapse;min-width:700px;">' +
        '<thead><tr>' +
        '<th style="' + S.th + 'width:8%">Ticket ID</th>' +
        '<th style="' + S.th + 'width:22%">Subject / Description</th>' +
        '<th style="' + S.th + 'width:12%">Customer</th>' +
        '<th style="' + S.th + 'width:9%">Raised On</th>' +
        '<th style="' + S.th + 'width:9%">Resolved On</th>' +
        '<th style="' + S.th + 'width:12%">Resolved By</th>' +
        '<th style="' + S.th + 'width:8%">Priority</th>' +
        '<th style="' + S.th + 'width:10%">Status</th>' +
        '<th style="' + S.th + 'width:10%">SLA</th>' +
        '</tr></thead>' +
        '<tbody>' +
        (ticketRows || '<tr><td colspan="9" style="' + S.td + 'text-align:center;color:#6c757d;padding:1rem;">No ticket data recorded for this project.</td></tr>') +
        '</tbody></table></div>';

    /* ── 5. PERFORMANCE SUMMARY ───────────────────────────────── */
    var summaryHtml =
        secTitle('Performance Summary', true) +
        '<div style="display:flex;gap:.6rem;margin-bottom:1rem;flex-wrap:wrap;page-break-inside:avoid;break-inside:avoid;">' +
        statBox(r.total_tickets,        'Total Tickets',     '#064e3b') +
        statBox(r.resolved_tickets,     'Resolved',          '#16a34a') +
        statBox(r.open_tickets,         'Open at Closure',   r.open_tickets > 0 ? '#d97706' : '#6c757d') +
        statBox(resolveRate + '%',      'Resolve Rate',      resolveRate >= 80 ? '#16a34a' : resolveRate >= 50 ? '#d97706' : '#dc2626') +
        statBox(r.sla_met,              'SLA Met',           '#16a34a') +
        statBox(r.sla_breached,         'SLA Breached',      r.sla_breached > 0 ? '#dc2626' : '#6c757d') +
        statBox(slaRate + '%',          'SLA Compliance',    slaRate >= 80 ? '#16a34a' : '#d97706') +
        statBox(r.avg_resolution_hrs + 'h', 'Avg Resolution','#064e3b') +
        '</div>';

    /* ── 6. SIGNATURE BLOCK ───────────────────────────────────── */
    var sigLineStyle = 'display:block;width:100%;border-bottom:1.5px solid #1a1a2e;margin-bottom:.3rem;height:42px;';
    var sigHtml =
        '<div style="page-break-inside:avoid;break-inside:avoid;">' +
        secTitle('Authorization &amp; Certification') +
        '<p style="font-size:.78rem;color:#6c757d;margin-bottom:1rem;">This report certifies the official closure of the above-named project. Authorized signatories confirm that all deliverables have been reviewed and the project is formally concluded.</p>' +
        '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:2rem;margin-top:1.5rem;">' +

        '<div>' +
        '<div style="font-size:.68rem;color:#6c757d;text-transform:uppercase;letter-spacing:.08em;margin-bottom:.3rem;">Prepared By</div>' +
        '<span style="' + sigLineStyle + '"></span>' +
        '<div style="font-size:.8rem;font-weight:600;">' + esc(r.focal_person||'_________________') + '</div>' +
        '<div style="font-size:.72rem;color:#6c757d;">Focal Person / Project Lead</div>' +
        '<div style="font-size:.72rem;color:#6c757d;margin-top:.1rem;">Dragon Coders</div>' +
        '</div>' +

        '<div>' +
        '<div style="font-size:.68rem;color:#6c757d;text-transform:uppercase;letter-spacing:.08em;margin-bottom:.3rem;">Reviewed &amp; Approved By</div>' +
        '<span style="' + sigLineStyle + '"></span>' +
        '<div style="font-size:.8rem;font-weight:600;">_________________</div>' +
        '<div style="font-size:.72rem;color:#6c757d;">Chief Executive Officer</div>' +
        '<div style="font-size:.72rem;color:#6c757d;margin-top:.1rem;">Dragon Coders</div>' +
        '</div>' +

        '<div>' +
        '<div style="font-size:.68rem;color:#6c757d;text-transform:uppercase;letter-spacing:.08em;margin-bottom:.3rem;">Official Stamp</div>' +
        '<div style="height:90px;width:90px;border:1.5px dashed #adb5bd;border-radius:50%;display:flex;align-items:center;justify-content:center;color:#adb5bd;font-size:.65rem;text-align:center;line-height:1.3;">Company<br>Stamp</div>' +
        '</div>' +

        '</div>' +
        '<div style="margin-top:1.4rem;display:grid;grid-template-columns:1fr 1fr;gap:2rem;">' +
        '<div><div style="font-size:.68rem;color:#6c757d;text-transform:uppercase;letter-spacing:.08em;margin-bottom:.3rem;">Date of Closure</div><span style="display:block;width:180px;border-bottom:1.5px solid #1a1a2e;height:28px;"></span></div>' +
        '<div style="font-size:.7rem;color:#6c757d;align-self:flex-end;text-align:right;">Dragon Coders &nbsp;·&nbsp; Strictly Confidential &nbsp;·&nbsp; Ref: ' + esc(r.project_key||'-') + '</div>' +
        '</div>' +
        '</div>';  /* end break-inside:avoid wrapper */

    /* ── ASSEMBLE ─────────────────────────────────────────────── */
    var html =
        '<div id="prReportContent" style="' + S.wrap + '">' +
        headerHtml +
        overviewHtml +
        teamCustHtml +
        ticketRegisterHtml +
        summaryHtml +
        sigHtml +
        '</div>';

    document.getElementById('prDetailBody').innerHTML = html;

    /* ── PDF download handler ────────────────────────────────────── */
    function doPdfDownload() {
        var el  = document.getElementById('prReportContent');
        var filename = (r.project_name + '_closure_report').replace(/\s+/g,'_') + '.pdf';
        if (btn1) { btn1.disabled = true; btn1.textContent = 'Generating…'; }
        if (btn2) { btn2.disabled = true; btn2.textContent = 'Generating…'; }
        var opt = {
            margin:       [10, 10, 10, 10],
            filename:     filename,
            image:        { type: 'jpeg', quality: 0.97 },
            html2canvas:  { scale: 2, useCORS: true, logging: false },
            jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' },
            pagebreak:    { mode: ['css', 'legacy'] }
        };
        html2pdf().set(opt).from(el).save().then(function () {
            if (btn1) { btn1.disabled = false; btn1.innerHTML = '<i class="bi bi-download me-1"></i>Download PDF'; }
            if (btn2) { btn2.disabled = false; btn2.innerHTML = '<i class="bi bi-download me-1"></i>Download PDF'; }
        });
    }
    var btn1 = null;
    var btn2 = document.getElementById('prDownloadBtn2');
    if (btn2) { btn2.onclick = doPdfDownload; }

    /* ── Show modal (stacked over reports list) ──────────────────── */
    var m1 = bootstrap.Modal.getInstance(document.getElementById('projectReportsModal'));
    if (m1) m1.hide();
    setTimeout(function() {
        new bootstrap.Modal(document.getElementById('prDetailModal')).show();
    }, 300);
};

window.prForwardReport = function() {
    var id = window._prCurrentReportId;
    var btn = document.getElementById('prForwardBtn');
    if (!id) {
        if (btn) { btn.innerHTML = '<i class="bi bi-exclamation-circle me-1"></i>No report selected (id=' + id + ')'; btn.className = 'btn btn-outline-danger'; }
        return;
    }
    if (btn) { btn.disabled = true; btn.innerHTML = '<span class="spinner-border spinner-border-sm me-1"></span>Forwarding…'; }
    jsonCall('/customer_support/admin_dashboard/report/forward', { report_id: id })
    .then(function(res) {
        if (res.error) {
            if (btn) { btn.disabled = false; btn.innerHTML = '<i class="bi bi-exclamation-circle me-1"></i>' + res.error; btn.className = 'btn btn-outline-danger'; }
            return;
        }
        var fwd = res.forwarded || 0;
        var dup = res.already_forwarded || 0;
        var msg, cls;
        if (fwd > 0) {
            msg = '<i class="bi bi-check-circle me-1"></i>Forwarded (' + fwd + ')';
            cls = 'btn btn-success';
        } else if (dup > 0) {
            msg = '<i class="bi bi-check-circle me-1"></i>Already forwarded';
            cls = 'btn btn-outline-secondary';
        } else {
            msg = '<i class="bi bi-exclamation-circle me-1"></i>No portal accounts found';
            cls = 'btn btn-outline-warning';
        }
        if (btn) { btn.disabled = true; btn.innerHTML = msg; btn.className = cls; }
    })
    .catch(function() {
        if (btn) { btn.disabled = false; btn.innerHTML = '<i class="bi bi-send me-1"></i>Forward to Customer'; btn.className = 'btn btn-outline-success'; }
    });
};

})();
