(function(){
'use strict';
var modalEl=document.getElementById('adminAutoAssignModal');
if(!modalEl){return;}

var enabledEl=document.getElementById('aaEnabled');
var durationEl=document.getElementById('aaDuration');
var strategyEl=document.getElementById('aaStrategy');
var statusEl=document.getElementById('aaStatusText');
var alertEl=document.getElementById('aaAlert');
var saveBtn=document.getElementById('aaSaveBtn');
var badgeEl=document.getElementById('autoAssignMenuBadge');

function showAlert(msg,type){
    if(!alertEl){return;}
    alertEl.className='alert alert-'+(type||'info');
    alertEl.textContent=msg;
    alertEl.classList.remove('d-none');
}

function hideAlert(){
    if(!alertEl){return;}
    alertEl.classList.add('d-none');
}

function setControlsEnabled(){
    var on=!!enabledEl.checked;
    durationEl.disabled=!on;
}

function updateMenuBadge(state){
    if(!badgeEl){return;}
    if(state.enabled){
        badgeEl.className='auto-assign-dot is-on';
        badgeEl.title='Enabled';
    } else {
        badgeEl.className='auto-assign-dot is-off';
        badgeEl.title='Disabled';
    }
}

function statusTextFrom(state){
    if(!state.enabled){return 'Status: Disabled';}
    var mins=parseInt(state.remaining_minutes||0,10);
    if(mins>=60){
        var hrs=(mins/60).toFixed(mins%60===0?0:1);
        return 'Status: Enabled for ~'+hrs+'h';
    }
    return 'Status: Enabled for ~'+mins+'m';
}

function fetchState(){
    return fetch('/customer_support/admin/auto_assignment/status',{
        method:'GET',
        credentials:'same-origin',
        headers:{'Accept':'application/json'}
    })
    .then(function(r){return r.text().then(function(txt){
        var data={};
        try{data=JSON.parse(txt||'{}');}catch(_e){throw new Error('Invalid server response.');}
        if(data.redirect_url){window.location.href=data.redirect_url;throw new Error('REDIRECT');}
        if(!r.ok||!data.success){throw new Error(data.error||('Request failed ('+r.status+')'));}
        return data;
    });});
}

function applyState(state){
    enabledEl.checked=!!state.enabled;
    strategyEl.value=state.strategy||'round_robin';
    var options=state.duration_options||[];
    if(options.length){
        var hasCurrent=options.some(function(v){return String(v)===String(durationEl.value);});
        if(!hasCurrent){durationEl.value=String(options[0]);}
    }
    setControlsEnabled();
    statusEl.textContent=statusTextFrom(state);
    updateMenuBadge(state);
}

function saveState(){
    hideAlert();
    saveBtn.disabled=true;
    var original=saveBtn.innerHTML;
    saveBtn.innerHTML='<i class="bi bi-arrow-repeat me-1"></i>Saving...';

    var body=new URLSearchParams();
    body.append('enabled',enabledEl.checked?'true':'false');
    body.append('duration_minutes',durationEl.value||'60');
    body.append('strategy',strategyEl.value||'round_robin');

    fetch('/customer_support/admin/auto_assignment/update',{
        method:'POST',
        credentials:'same-origin',
        headers:{'Content-Type':'application/x-www-form-urlencoded','Accept':'application/json'},
        body:body.toString()
    })
    .then(function(r){return r.text().then(function(txt){
        var data={};
        try{data=JSON.parse(txt||'{}');}catch(_e){throw new Error('Invalid server response.');}
        if(data.redirect_url){window.location.href=data.redirect_url;throw new Error('REDIRECT');}
        if(!r.ok||!data.success){throw new Error(data.error||('Request failed ('+r.status+')'));}
        return data;
    });})
    .then(function(state){
        applyState(state);
        showAlert('Auto-assignment settings updated.', 'success');
    })
    .catch(function(err){
        if(err&&err.message!=='REDIRECT'){showAlert(err.message||'Failed to update settings.','danger');}
    })
    .finally(function(){
        saveBtn.disabled=false;
        saveBtn.innerHTML=original;
    });
}

    enabledEl.addEventListener('change',setControlsEnabled);
    saveBtn.addEventListener('click',saveState);
    modalEl.addEventListener('show.bs.modal',function(){
        hideAlert();
        statusEl.textContent='Status: Loading...';
        fetchState().then(applyState).catch(function(err){
            if(err&&err.message!=='REDIRECT'){
                showAlert(err.message||'Failed to load status.','danger');
                statusEl.textContent='Status: Unable to load';
            }
        });
    });

    // Keep dropdown badge fresh on page load.
    fetchState().then(applyState).catch(function(_e){});
})();
