document.addEventListener('DOMContentLoaded', function () {
    var logoutModal    = document.getElementById('adminLogoutWarningModal');
    var modalStayBtn   = document.getElementById('adminModalStayBtn');
    var modalLogoutBtn = document.getElementById('adminModalLogoutBtn');

    // Push 3 buffer entries so rapid back presses can't skip past the trap
    history.pushState({ adminTrap: true }, '', window.location.href);
    history.pushState({ adminTrap: true }, '', window.location.href);
    history.pushState({ adminTrap: true }, '', window.location.href);

    window.addEventListener('popstate', function (e) {
        // Tab-navigation pop — restore the tab, don't show logout warning
        if (e.state && e.state.tab) {
            if (window._activateTab) window._activateTab(e.state.tab);
            return;
        }
        // Reached a trap entry — re-arm buffer and show logout warning
        history.pushState({ adminTrap: true }, '', window.location.href);
        history.pushState({ adminTrap: true }, '', window.location.href);
        history.pushState({ adminTrap: true }, '', window.location.href);
        if (logoutModal) logoutModal.classList.add('show');
    });

    // Re-arm after bfcache restore
    window.addEventListener('pageshow', function (e) {
        if (e.persisted) {
            history.pushState({ adminTrap: true }, '', window.location.href);
            history.pushState({ adminTrap: true }, '', window.location.href);
            history.pushState({ adminTrap: true }, '', window.location.href);
        }
    });

    // "Stay on Page" button — just close the modal
    if (modalStayBtn) {
        modalStayBtn.addEventListener('click', function () {
            if (logoutModal) logoutModal.classList.remove('show');
        });
    }

    // "Logout Properly" button — go to proper logout route
    if (modalLogoutBtn) {
        modalLogoutBtn.addEventListener('click', function () {
            window.location.href = '/customer_support/logout_manual';
        });
    }

    // Close modal if admin clicks the dark backdrop
    if (logoutModal) {
        logoutModal.addEventListener('click', function (e) {
            if (e.target === logoutModal) {
                logoutModal.classList.remove('show');
            }
        });
    }
});
