(function(){
'use strict';
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
var TA_DONE_KEY='cs_ticket_action_done_v1';
function taGetDoneSet(){
    try{
        var raw=localStorage.getItem(TA_DONE_KEY)||'[]';
        var arr=JSON.parse(raw);
        return new Set(Array.isArray(arr)?arr:[]);
    }catch(_e){
        return new Set();
    }
}
function taSaveDoneSet(setObj){
    try{
        localStorage.setItem(TA_DONE_KEY, JSON.stringify(Array.from(setObj)));
    }catch(_e){}
}
function taRemoveAttention(ticketId){
    if(!ticketId){return;}
    document.querySelectorAll('.ta-ticket-row[data-ticket-id="'+ticketId+'"], .ta-ticket-card[data-ticket-id="'+ticketId+'"]').forEach(function(el){
        el.classList.remove('ta-ticket-attn');
        var dot=el.querySelector('.ta-attn-dot');
        if(dot){dot.remove();}
    });
}
function taMarkLatestThree(){
    var done=taGetDoneSet();
    var rows=Array.prototype.slice.call(document.querySelectorAll('.ta-ticket-row'));
    var marked=0;
    rows.forEach(function(row){
        if(marked>=3){return;}
        var hasAction=!!row.querySelector('form.assign-form, form.mtc-assign-form');
        var ticketId=row.getAttribute('data-ticket-id');
        if(!hasAction||!ticketId||done.has(ticketId)){return;}
        row.classList.add('ta-ticket-attn');
        if(!row.querySelector('.ta-attn-dot')){
            var subjectLink=row.querySelector('td:nth-child(2) a')||row.querySelector('a.admin-ticket-open');
            if(subjectLink){
                var dot=document.createElement('span');
                dot.className='ta-attn-dot';
                subjectLink.appendChild(dot);
            }
        }
        var card=document.querySelector('.ta-ticket-card[data-ticket-id="'+ticketId+'"]');
        if(card){
            card.classList.add('ta-ticket-attn');
            if(!card.querySelector('.ta-attn-dot')){
                var cardTop=card.querySelector('.mtc-top')||card;
                var dot2=document.createElement('span');
                dot2.className='ta-attn-dot';
                cardTop.appendChild(dot2);
            }
        }
        marked+=1;
    });
}

function handleAssignForm(form){
    form.addEventListener('submit',function(e){
        e.preventDefault();

        // Read the selected agent name immediately from the dropdown
        var sel=form.querySelector('select[name="assigned_to"]');
        var assignedName=sel?sel.options[sel.selectedIndex].text.trim():'';
        if(!assignedName||!sel||!sel.value){return;}

        // ── Optimistic update: show success instantly, before the request ──
        var cell=form.closest('td,div');
        var originalCellHtml=cell?cell.innerHTML:null;
        if(cell){
            cell.innerHTML='<span class="badge bg-success"><i class="bi bi-check-circle me-1"></i>'+esc(assignedName)+'</span>';
        }
        showToast('Assigned to '+esc(assignedName),'success');

        // ── Fire request in background ────────────────────────────────────
        var data=new FormData(form);
        fetch(form.action,{
            method:'POST',
            credentials:'same-origin',
            body:data
        })
        .then(function(r){return r.json();})
        .then(function(res){
            if(!res.success){
                // Revert on server error
                if(cell&&originalCellHtml!==null){cell.innerHTML=originalCellHtml;}
                showToast(res.error||'Assignment failed — please try again','danger');
                // Re-attach handler after revert
                var newForm=cell&&cell.querySelector('form');
                if(newForm){handleAssignForm(newForm);}
            }else{
                var ticketRow=form.closest('.ta-ticket-row');
                var ticketCard=form.closest('.ta-ticket-card');
                var ticketId=(ticketRow&&ticketRow.getAttribute('data-ticket-id'))||(ticketCard&&ticketCard.getAttribute('data-ticket-id'));
                if(ticketId){
                    var done=taGetDoneSet();
                    done.add(String(ticketId));
                    taSaveDoneSet(done);
                    taRemoveAttention(String(ticketId));
                }
            }
        })
        .catch(function(){
            // Revert on network error
            if(cell&&originalCellHtml!==null){cell.innerHTML=originalCellHtml;}
            showToast('Network error — assignment may not have saved','danger');
            var newForm=cell&&cell.querySelector('form');
            if(newForm){handleAssignForm(newForm);}
        });
    });
}

function showToast(msg,type){
    var t=document.createElement('div');
    t.className='alert alert-'+type+' alert-dismissible position-fixed shadow';
    t.style.cssText='bottom:1.5rem;right:1.5rem;z-index:9999;min-width:280px;';
    t.innerHTML='<i class="bi bi-'+(type==='success'?'check-circle':'exclamation-triangle')+' me-2"></i>'+esc(msg)+'<button type="button" class="btn-close" data-bs-dismiss="alert"></button>';
    document.body.appendChild(t);
    setTimeout(function(){t.remove();},4000);
}

document.addEventListener('DOMContentLoaded',function(){
    document.querySelectorAll('.assign-form,.mtc-assign-form').forEach(handleAssignForm);
    taMarkLatestThree();
});
})();
