(function () {
'use strict';

var _projId   = null;
var _docsLoaded = false;

function getCSRF() {
    var el = document.querySelector('input[name="csrf_token"]');
    return el ? el.value : '';
}

var jsonCall = window.jsonCall || function(url, body) {
    return fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-CSRFToken': getCSRF() },
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: body || {} })
    }).then(function (r) { return r.json(); }).then(function (d) { return d.result || d; });
};
window.jsonCall = jsonCall;

function esc(s) {
    var d = document.createElement('span');
    d.textContent = String(s || '');
    return d.innerHTML;
}

function showMsg(elId, text, type) {
    var el = document.getElementById(elId);
    if (!el) return;
    el.innerHTML = '<div class="pd-alert pd-alert-' + type + '"><i class="bi bi-' + (type === 'success' ? 'check-circle' : 'exclamation-triangle') + '"></i>' + esc(text) + '</div>';
    el.style.display = '';
    setTimeout(function () { el.style.display = 'none'; }, 3800);
}

// ── Open / Close ──────────────────────────────────────────────────────────
window.openProjDrawer = function (dataset) {
    _projId     = dataset.projectId || null;
    _docsLoaded = false;

    var codeEl = document.getElementById('pdCode');
    var nameEl = document.getElementById('pdName');
    var typeEl = document.getElementById('pdType');
    if (codeEl) codeEl.textContent = dataset.projectCode || '';
    if (nameEl) nameEl.textContent = dataset.projectName || 'Project';
    if (typeEl) typeEl.textContent = dataset.projectType || '';

    // Highlight the active project card so the drawer appears to extend from it
    document.querySelectorAll('.pj-card--active').forEach(function (c) {
        c.classList.remove('pj-card--active');
    });
    var activeCard = document.getElementById('pjCard-' + dataset.projectId);
    if (activeCard) activeCard.classList.add('pj-card--active');

    switchPdTab('team');
    loadTeam();

    document.getElementById('projDrawerOverlay').classList.add('pdOpen');
    document.getElementById('projDrawer').classList.add('pdOpen');
    document.body.style.overflow = 'hidden';
};

window.closeProjDrawer = function () {
    document.getElementById('projDrawerOverlay').classList.remove('pdOpen');
    document.getElementById('projDrawer').classList.remove('pdOpen');
    document.body.style.overflow = '';
    document.querySelectorAll('.pj-card--active').forEach(function (c) {
        c.classList.remove('pj-card--active');
    });
};

document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape' && document.getElementById('projDrawer').classList.contains('pdOpen')) {
        closeProjDrawer();
    }
});

// ── Tab Switcher ──────────────────────────────────────────────────────────
window.switchPdTab = function (tab) {
    ['team', 'docs'].forEach(function (t) {
        var capT = t.charAt(0).toUpperCase() + t.slice(1);
        var btn   = document.getElementById('pdTab' + capT);
        var panel = document.getElementById('pdPanel' + capT);
        var active = (t === tab);
        if (btn)   { btn.classList[active ? 'add' : 'remove']('pdTabActive'); btn.setAttribute('aria-selected', active); }
        if (panel) panel.style.display = active ? '' : 'none';
    });
    if (tab === 'docs' && !_docsLoaded) { loadDocs(); _docsLoaded = true; }
};

// ═════════════════════════════════════════════════════════════════════════
// TEAM
// ═════════════════════════════════════════════════════════════════════════
function loadTeam() {
    if (!_projId) return;
    var list  = document.getElementById('pdMemberList');
    var empty = document.getElementById('pdMemberEmpty');
    if (list)  list.innerHTML  = '<div class="pd-loading"><div class="spinner-border spinner-border-sm me-2" style="width:14px;height:14px"></div>Loading team…</div>';
    if (empty) empty.style.display = 'none';

    jsonCall('/customer_support/admin_dashboard/focal_persons', {}).then(function (res) {
        var sel = document.getElementById('pdFocalSelect');
        if (!sel) return;
        sel.innerHTML = '<option value="">— Select focal person —</option>';
        (res.users || []).forEach(function (u) {
            var opt = document.createElement('option');
            opt.value = u.id;
            opt.textContent = u.name + (u.email ? ' (' + u.email + ')' : '');
            sel.appendChild(opt);
        });
    });

    jsonCall('/customer_support/admin_dashboard/projects/' + _projId + '/members', {}).then(function (res) {
        if (!list) return;
        list.innerHTML = '';
        if (res.error) { showMsg('pdMemberMsg', res.error, 'danger'); return; }
        renderFocal(res.focal || null);
        var focal = res.focal;
        var fSel  = document.getElementById('pdFocalSelect');
        if (focal && focal.user_id && fSel) fSel.value = focal.user_id;

        var members = res.members || [];
        if (!members.length) { if (empty) empty.style.display = ''; }
        else members.forEach(appendMemberRow);

        updateTeamBadge(members.length + (focal ? 1 : 0));
    });
}

function renderFocal(m) {
    var cur       = document.getElementById('pdFocalCurrent');
    var removeBtn = document.getElementById('pdRemoveFocalBtn');
    if (!cur) return;
    if (!m) {
        cur.innerHTML = '<p style="font-size:.78rem;color:#9ca3af;margin:0;font-style:italic">No focal person assigned yet.</p>';
        if (removeBtn) removeBtn.style.display = 'none';
        return;
    }
    cur.innerHTML =
        '<div class="pd-member-row" style="margin-bottom:0">' +
            '<div class="pd-avatar pd-avatar-focal">' + esc(m.initials) + '</div>' +
            '<div class="pd-member-info">' +
                '<span class="pd-member-name">' + esc(m.name) + '</span>' +
                '<span class="pd-member-email">' + esc(m.email || '') + '</span>' +
            '</div>' +
            '<span class="pd-role-tag pd-role-focal">Focal Person</span>' +
        '</div>';
    if (removeBtn) removeBtn.style.display = '';
}

function appendMemberRow(m) {
    var list  = document.getElementById('pdMemberList');
    var empty = document.getElementById('pdMemberEmpty');
    if (!list) return;
    if (empty) empty.style.display = 'none';

    var row = document.createElement('div');
    row.className = 'pd-member-row';
    row.dataset.memberId = m.id;
    row.innerHTML =
        '<div class="pd-avatar">' + esc(m.initials) + '</div>' +
        '<div class="pd-member-info">' +
            '<span class="pd-member-name">' + esc(m.name) + '</span>' +
            '<span class="pd-member-email">' + esc(m.email || '') + '</span>' +
        '</div>' +
        '<span class="pd-role-tag">' + esc(m.role_label) + '</span>' +
        '<button class="pd-rm-btn" data-member-id="' + m.id + '" title="Remove member"><i class="bi bi-person-dash"></i></button>';

    row.querySelector('.pd-rm-btn').addEventListener('click', function () {
        var mid = this.dataset.memberId;
        jsonCall('/customer_support/admin_dashboard/projects/members/' + mid + '/remove', {})
            .then(function (res) {
                if (res.success) {
                    row.remove();
                    if (list && !list.querySelector('.pd-member-row') && empty) empty.style.display = '';
                    showMsg('pdMemberMsg', 'Member removed.', 'success');
                    reCountTeamBadge();
                } else {
                    showMsg('pdMemberMsg', res.error || 'Failed to remove.', 'danger');
                }
            });
    });
    list.appendChild(row);
}

function updateTeamBadge(count) {
    var badge = document.getElementById('pdTeamBadge');
    if (!badge) return;
    if (count > 0) { badge.textContent = count; badge.style.display = ''; }
    else badge.style.display = 'none';
}

function reCountTeamBadge() {
    var rows  = (document.getElementById('pdMemberList') || {}).querySelectorAll ? document.getElementById('pdMemberList').querySelectorAll('.pd-member-row').length : 0;
    var focal = (document.getElementById('pdRemoveFocalBtn') || {}).style && document.getElementById('pdRemoveFocalBtn').style.display !== 'none' ? 1 : 0;
    updateTeamBadge(rows + focal);
}

document.addEventListener('DOMContentLoaded', function () {
    var assignBtn  = document.getElementById('pdAssignFocalBtn');
    var removeBtn  = document.getElementById('pdRemoveFocalBtn');
    var addMbrBtn  = document.getElementById('pdAddMemberBtn');

    if (assignBtn) {
        assignBtn.addEventListener('click', function () {
            var uid = document.getElementById('pdFocalSelect').value;
            if (!uid) { showMsg('pdFocalMsg', 'Please select a focal person.', 'danger'); return; }
            jsonCall('/customer_support/admin_dashboard/projects/' + _projId + '/focal/assign', { user_id: parseInt(uid) })
                .then(function (res) {
                    if (res.success) { renderFocal(res.member); showMsg('pdFocalMsg', 'Focal person assigned.', 'success'); reCountTeamBadge(); }
                    else showMsg('pdFocalMsg', res.error || 'Failed to assign.', 'danger');
                });
        });
    }

    if (removeBtn) {
        removeBtn.addEventListener('click', function () {
            jsonCall('/customer_support/admin_dashboard/projects/' + _projId + '/focal/remove', {})
                .then(function (res) {
                    if (res.success) { renderFocal(null); showMsg('pdFocalMsg', 'Focal person removed.', 'success'); reCountTeamBadge(); }
                    else showMsg('pdFocalMsg', res.error || 'Failed.', 'danger');
                });
        });
    }

    if (addMbrBtn) {
        addMbrBtn.addEventListener('click', function () {
            var name  = (document.getElementById('pdMemberName').value || '').trim();
            var email = (document.getElementById('pdMemberEmail').value || '').trim();
            var role  = document.getElementById('pdMemberRole').value;
            if (!name) { showMsg('pdMemberMsg', 'Full name is required.', 'danger'); return; }
            jsonCall('/customer_support/admin_dashboard/projects/' + _projId + '/members/add', { name: name, email: email, role: role })
                .then(function (res) {
                    if (res.success) {
                        appendMemberRow(res.member);
                        document.getElementById('pdMemberName').value  = '';
                        document.getElementById('pdMemberEmail').value = '';
                        showMsg('pdMemberMsg', 'Member added successfully.', 'success');
                        reCountTeamBadge();
                    } else {
                        showMsg('pdMemberMsg', res.error || 'Failed to add member.', 'danger');
                    }
                });
        });
    }
});

// ═════════════════════════════════════════════════════════════════════════
// DOCUMENTS
// ═════════════════════════════════════════════════════════════════════════
var FILE_ICONS  = { pdf:'bi-file-earmark-pdf-fill', docx:'bi-file-earmark-word-fill', xlsx:'bi-file-earmark-excel-fill', txt:'bi-file-earmark-text-fill' };
var FILE_COLORS = { pdf:'#ef4444', docx:'#059669', xlsx:'#16a34a', txt:'#64748b' };
var STATE_LABELS = { pending:'Processing…', ready:'Ready', error:'Error' };

function loadDocs() {
    if (!_projId) return;
    var docList  = document.getElementById('pdDocList');
    var docEmpty = document.getElementById('pdDocEmpty');
    if (docList)  docList.innerHTML  = '<div class="pd-loading"><div class="spinner-border spinner-border-sm me-2" style="width:14px;height:14px"></div>Loading documents…</div>';
    if (docEmpty) docEmpty.style.display = 'none';

    jsonCall('/customer_support/admin_dashboard/projects/' + _projId + '/documents', {}).then(function (res) {
        if (!docList) return;
        docList.innerHTML = '';
        if (res.error) { docList.innerHTML = '<p style="color:#ef4444;font-size:.8rem;margin:0">' + esc(res.error) + '</p>'; return; }
        var docs = res.documents || [];
        updateDocsBadge(docs.length);
        if (!docs.length) { if (docEmpty) docEmpty.style.display = ''; return; }
        docs.forEach(appendDocRow);
    });
}

function appendDocRow(doc) {
    var docList  = document.getElementById('pdDocList');
    var docEmpty = document.getElementById('pdDocEmpty');
    if (!docList) return;
    if (docEmpty) docEmpty.style.display = 'none';

    var icon       = FILE_ICONS[doc.file_type]  || 'bi-file-earmark-fill';
    var color      = FILE_COLORS[doc.file_type] || '#64748b';
    var stateLabel = STATE_LABELS[doc.state]    || doc.state;
    var stateClass = doc.state === 'ready' ? 'pd-state-ready' : (doc.state === 'error' ? 'pd-state-error' : 'pd-state-pending');

    var row = document.createElement('div');
    row.className = 'pd-doc-row';
    row.dataset.docId = doc.id;
    row.innerHTML =
        '<div class="pd-doc-icon" style="color:' + color + '"><i class="bi ' + icon + '"></i></div>' +
        '<div class="pd-doc-info">' +
            '<span class="pd-doc-name">' + esc(doc.name) + '</span>' +
            '<span class="pd-doc-meta">' + esc(doc.filename) + ' · ' + esc(doc.created) + '</span>' +
        '</div>' +
        '<span class="pd-doc-state ' + stateClass + '">' + stateLabel + '</span>' +
        '<button class="pd-del-btn" data-doc-id="' + doc.id + '" title="Delete document"><i class="bi bi-trash3"></i></button>';

    row.querySelector('.pd-del-btn').addEventListener('click', function () {
        if (!confirm('Delete "' + doc.name + '"?\nThis cannot be undone.')) return;
        jsonCall('/customer_support/admin_dashboard/documents/' + doc.id + '/delete', {})
            .then(function (res) {
                if (res.success) {
                    row.remove();
                    var remaining = docList.querySelectorAll('.pd-doc-row').length;
                    if (!remaining && docEmpty) docEmpty.style.display = '';
                    updateDocsBadge(remaining);
                    showMsg('pdUploadMsg', 'Document deleted.', 'success');
                } else {
                    showMsg('pdUploadMsg', res.error || 'Failed to delete.', 'danger');
                }
            });
    });
    docList.appendChild(row);
}

function updateDocsBadge(count) {
    var badge = document.getElementById('pdDocsBadge');
    if (!badge) return;
    if (count > 0) { badge.textContent = count; badge.style.display = ''; }
    else badge.style.display = 'none';
}

// Drag-and-drop
window.pdHandleDrop = function (e) {
    e.preventDefault();
    var zone = document.getElementById('pdUploadZone');
    if (zone) zone.classList.remove('pdDragOver');
    var files = e.dataTransfer && e.dataTransfer.files;
    if (files && files.length) {
        var input = document.getElementById('pdFileInput');
        try { var dt = new DataTransfer(); dt.items.add(files[0]); input.files = dt.files; } catch (ex) {}
        pdFileSelected(input);
    }
};

// File selected — show preview + auto-fill name
window.pdFileSelected = function (input) {
    var preview = document.getElementById('pdFilePreview');
    if (!preview) return;
    if (!input.files || !input.files.length) { preview.style.display = 'none'; return; }
    var f = input.files[0];
    var size = f.size > 1048576 ? (f.size / 1048576).toFixed(1) + ' MB' : Math.round(f.size / 1024) + ' KB';
    preview.className = 'pd-file-preview';
    preview.innerHTML =
        '<i class="bi bi-file-earmark" style="font-size:1.1rem;color:#065f46;flex-shrink:0"></i>' +
        '<span class="pd-file-preview-name">' + esc(f.name) + '</span>' +
        '<span class="pd-file-preview-size">' + size + '</span>' +
        '<button class="pd-file-preview-rm" title="Remove file" onclick="document.getElementById(\'pdFileInput\').value=\'\';document.getElementById(\'pdFilePreview\').style.display=\'none\'"><i class="bi bi-x-lg"></i></button>';
    preview.style.display = '';
    var nameEl = document.getElementById('pdDocName');
    if (nameEl && !nameEl.value.trim()) {
        nameEl.value = f.name.replace(/\.[^.]+$/, '');
    }
};

document.addEventListener('DOMContentLoaded', function () {
    var uploadBtn = document.getElementById('pdUploadBtn');
    if (!uploadBtn) return;

    uploadBtn.addEventListener('click', function () {
        var name      = (document.getElementById('pdDocName').value || '').trim();
        var fileInput = document.getElementById('pdFileInput');
        var category  = document.getElementById('pdDocCategory').value;

        if (!name)                        { showMsg('pdUploadMsg', 'Document name is required.', 'danger');    return; }
        if (!fileInput || !fileInput.files.length) { showMsg('pdUploadMsg', 'Please select or drop a file.', 'danger'); return; }
        if (!_projId)                     { showMsg('pdUploadMsg', 'No project selected.', 'danger');           return; }

        var formData = new FormData();
        formData.append('name', name);
        formData.append('category', category);
        formData.append('project_id', _projId);
        formData.append('file', fileInput.files[0]);
        formData.append('ajax', '1');
        var csrf = document.querySelector('input[name="csrf_token"]');
        if (csrf) formData.append('csrf_token', csrf.value);

        var btn = this;
        btn.disabled = true;
        btn.innerHTML = '<span class="spinner-border spinner-border-sm me-2" style="width:13px;height:13px"></span>Uploading…';

        fetch('/customer_support/knowledge/upload', { method: 'POST', credentials: 'same-origin', cache: 'no-store', body: formData })
            .then(function (r) { return r.json(); })
            .then(function (res) {
                if (res.error) {
                    showMsg('pdUploadMsg', res.error, 'danger');
                } else {
                    document.getElementById('pdDocName').value      = '';
                    document.getElementById('pdDocCategory').value  = 'projects';
                    fileInput.value                                  = '';
                    var prev = document.getElementById('pdFilePreview');
                    if (prev) prev.style.display = 'none';
                    showMsg('pdUploadMsg', 'Document uploaded. Processing has started in the background.', 'success');
                    loadDocs();
                    setTimeout(loadDocs, 400);
                }
            })
            .catch(function () { showMsg('pdUploadMsg', 'Upload failed. Please try again.', 'danger'); })
            .finally(function () {
                btn.disabled = false;
                btn.innerHTML = '<i class="bi bi-cloud-upload"></i> Upload Document';
            });
    });
});

})();
